 55→/**
 56→ * Extract project name from path (last segment)
 57→ */
 58→function extractProjectName(projectPath: string): string {
 59→	if (!projectPath) return "";
 60→	const segments = projectPath.replace(/\\/g, "/").split("/").filter(Boolean);
 61→	return segments[segments.length - 1] || projectPath;
 62→}
 63→
 64→/**
 65→ * Extract repository name from path
 66→ */
 67→function extractRepositoryName(projectPath: string): string {
