190→export async function getSessionAnalyticsSummary(
191→	orgId: string,
192→	params: {
193→		days?: number;
194→		user_id?: string;
195→		project_path?: string;
196→	} = {},
197→): Promise<SessionAnalyticsSummary> {
198→	const { days = 30, user_id, project_path } = params;
199→	const org = escapeString(orgId);
200→	const d = Number(days);
201→
202→	let filters = "";
203→	if (user_id) {
204→		filters += ` AND user_id = '${escapeString(user_id)}'`;
205→	}
206→	if (project_path) {
207→		filters += ` AND project_path = '${escapeString(project_path)}'`;
208→	}
209→
210→	const query = `
211→    WITH totals AS (
212→      SELECT
213→        COUNT(*) as cnt_sessions,
214→        SUM(total_interactions) as sum_interactions,
215→        SUM(quick_responses) as sum_quick_responses,
216→        SUM(long_pauses) as sum_long_pauses,
217→        ifNull(AVG(actual_duration_min), 0) as avg_duration,
218→        ifNull(AVG(total_interactions), 0) as avg_interactions,
219→        ifNull(AVG(avg_period_sec), 0) as avg_response,
220→        ifNull(AVG(median_period_sec), 0) as med_response,
221→        countIf(length(subagent_types) > 0) as cnt_subagents,
222→        countIf(length(skills) > 0) as cnt_skills,
223→        countIf(length(slash_commands) > 0) as cnt_slash
224→      FROM rudel.session_analytics
