228→    )
229→    SELECT
230→      cnt_sessions as total_sessions,
231→      sum_interactions as total_interactions,
232→      ifNull(round(avg_duration, 2), 0) as avg_session_duration_min,
233→      ifNull(round(avg_interactions, 2), 0) as avg_interactions_per_session,
234→      ifNull(round(avg_response, 2), 0) as avg_response_time_sec,
235→      ifNull(round(med_response, 2), 0) as median_response_time_sec,
236→      round(sum_quick_responses * 100.0 / if(sum_interactions > 0, sum_interactions, 1), 2) as quick_response_rate,
237→      round(sum_long_pauses * 100.0 / if(sum_interactions > 0, sum_interactions, 1), 2) as long_pause_rate,
238→      round(cnt_subagents * 100.0 / if(cnt_sessions > 0, cnt_sessions, 1), 2) as subagents_adoption_rate,
239→      round(cnt_skills * 100.0 / if(cnt_sessions > 0, cnt_sessions, 1), 2) as skills_adoption_rate,
240→      round(cnt_slash * 100.0 / if(cnt_sessions > 0, cnt_sessions, 1), 2) as slash_commands_adoption_rate
241→    FROM totals
242→  `;
243→
244→	const results = await queryClickhouse<SessionAnalyticsSummary>(query);
245→
246→	const defaults: SessionAnalyticsSummary = {
247→		total_sessions: 0,
248→		total_interactions: 0,
249→		avg_session_duration_min: 0,
250→		avg_interactions_per_session: 0,
