274→/**
275→ * Get session analytics summary with period-over-period comparison
276→ */
277→export async function getSessionAnalyticsSummaryComparison(
278→	orgId: string,
279→	params: {
280→		days?: number;
281→		user_id?: string;
282→		project_path?: string;
283→	} = {},
284→) {
285→	const { days = 7, user_id, project_path } = params;
286→	const org = escapeString(orgId);
287→	const d = Number(days);
288→	const previousDays = d * 2;
289→
290→	let filters = "";
291→	if (user_id) {
292→		filters += ` AND user_id = '${escapeString(user_id)}'`;
293→	}
294→	if (project_path) {
295→		filters += ` AND project_path = '${escapeString(project_path)}'`;
296→	}
297→
298→	const summarySQL = (dateCondition: string) => `
299→    WITH totals AS (
300→      SELECT
301→        COUNT(*) as cnt_sessions,
302→        ifNull(AVG(actual_duration_min), 0) as avg_duration,
303→        ifNull(AVG(avg_period_sec), 0) as avg_response,
304→        countIf(length(subagent_types) > 0) as cnt_subagents,
305→        countIf(length(skills) > 0) as cnt_skills,
306→        countIf(length(slash_commands) > 0) as cnt_slash
307→      FROM rudel.session_analytics
308→      WHERE ${dateCondition}
309→        AND organization_id = '${org}'
310→        ${filters}
311→    )
312→    SELECT
313→      cnt_sessions as total_sessions,
314→      ifNull(round(avg_duration, 2), 0) as avg_session_duration_min,
315→      ifNull(round(avg_response, 2), 0) as avg_response_time_sec,
316→      round(cnt_subagents * 100.0 / if(cnt_sessions > 0, cnt_sessions, 1), 2) as subagents_adoption_rate,
317→      round(cnt_skills * 100.0 / if(cnt_sessions > 0, cnt_sessions, 1), 2) as skills_adoption_rate,
318→      round(cnt_slash * 100.0 / if(cnt_sessions > 0, cnt_sessions, 1), 2) as slash_commands_adoption_rate
319→    FROM totals
320→  `;
321→
322→	const currentQuery = summarySQL(buildDateFilter(d));
323→	const previousQuery = summarySQL(
324→		`session_date >= now64(3) - INTERVAL ${previousDays} DAY AND session_date < now64(3) - INTERVAL ${d} DAY`,
325→	);
326→
327→	const [currentData, previousData] = await Promise.all([
328→		queryClickhouse<SessionSummaryComparisonPeriod>(currentQuery),
329→		queryClickhouse<SessionSummaryComparisonPeriod>(previousQuery),
330→	]);
331→
332→	const defaultPeriod: SessionSummaryComparisonPeriod = {
333→		total_sessions: 0,
334→		avg_session_duration_min: 0,
335→		avg_response_time_sec: 0,
336→		subagents_adoption_rate: 0,
337→		skills_adoption_rate: 0,
338→		slash_commands_adoption_rate: 0,
339→	};
340→
341→	// Coalesce nulls from ClickHouse (AVG on 0 rows returns null despite ifNull)
342→	const coalesce = (
343→		row: SessionSummaryComparisonPeriod | undefined,
344→	): SessionSummaryComparisonPeriod => {
345→		if (!row) return { ...defaultPeriod };
346→		return Object.fromEntries(
347→			Object.entries(defaultPeriod).map(([key, def]) => [
348→				key,
349→				(row as unknown as Record<string, unknown>)[key] ?? def,
350→			]),
351→		) as SessionSummaryComparisonPeriod;
352→	};
353→	const current = coalesce(currentData[0]);
354→	const previous = coalesce(previousData[0]);
355→
356→	const calculateChange = (curr: number, prev: number) => {
357→		if (!prev || prev === 0) return 0;
358→		return ((curr - prev) / prev) * 100;
359→	};
360→
361→	const changes = {
362→		total_sessions: calculateChange(
363→			current.total_sessions || 0,
364→			previous.total_sessions || 0,
365→		),
366→		avg_session_duration_min: calculateChange(
367→			current.avg_session_duration_min || 0,
368→			previous.avg_session_duration_min || 0,
369→		),
370→		avg_response_time_sec: calculateChange(
371→			current.avg_response_time_sec || 0,
372→			previous.avg_response_time_sec || 0,
373→		),
374→	};
375→
376→	return { current, previous, changes };
377→}
