434→      SUM(long_pauses) as count,
435→      round(SUM(long_pauses) * 100.0 / (SELECT total_count FROM total), 2) as percentage
436→    FROM rudel.session_analytics
437→    WHERE ${buildDateFilter(d)}
438→      AND organization_id = '${org}'
439→      ${filters}
440→
441→    ORDER BY count DESC
442→  `;
443→
444→	return queryClickhouse<{ bucket: string; count: number; percentage: number }>(
445→		query,
