499→		used_skills: "if(length(skills) > 0, 1, 0)",
500→		used_slash_commands: "if(length(slash_commands) > 0, 1, 0)",
501→		used_subagents: "if(length(subagent_types) > 0, 1, 0)",
502→	};
503→
504→	const dimensionExpression = dimensionExpressions[dimension] || dimension;
505→	const splitByExpression = split_by
506→		? dimensionExpressions[split_by] || split_by
507→		: null;
508→
509→	let filters = "";
510→	if (user_id) {
