523→        ${splitByExpression} as split_value,
524→        ${metricExpression} as metric_value
525→      FROM rudel.session_analytics
526→      WHERE ${buildDateFilter(d)}
527→        AND organization_id = '${org}'
528→        ${filters}
529→      GROUP BY dimension_value, split_value
530→      ORDER BY metric_value DESC
531→    `;
532→	} else {
