534→      SELECT
535→        ${dimensionExpression} as dimension_value,
536→        ${metricExpression} as metric_value
537→      FROM rudel.session_analytics
538→      WHERE ${buildDateFilter(d)}
539→        AND organization_id = '${org}'
540→        ${filters}
541→      GROUP BY dimension_value
542→      ORDER BY metric_value DESC
543→      LIMIT ${lim}
544→    `;
545→	}
546→
547→	interface DimensionRow {
