550→		metric_value: number;
551→	}
552→
553→	const results = await queryClickhouse<DimensionRow>(query);
554→
555→	if (split_by) {
556→		const grouped = new Map<string, Record<string, number>>();
557→		const totalMetric = new Map<string, number>();
558→
