179→	const previous = previousData[0] || { total_sessions: 0 };
180→
181→	// Insight 1: Session trend analysis
182→	if (current && previous) {
183→		const sessionChange =
184→			previous.total_sessions > 0
185→				? ((current.total_sessions - previous.total_sessions) /
186→						previous.total_sessions) *
187→					100
188→				: 0;
189→
190→		if (Math.abs(sessionChange) >= 10) {
191→			const direction = sessionChange > 0 ? "up" : "down";
192→			const severity = sessionChange > 0 ? "positive" : "warning";
193→			insights.push({
194→				type: "trend",
