393→		avg_success_score: number;
394→		high_quality_sessions: number;
395→	}
396→
397→	const [currentData, previousData] = await Promise.all([
398→		queryClickhouse<SuccessRateStats>(currentQuery),
399→		queryClickhouse<SuccessRateStats>(previousQuery),
400→	]);
401→
402→	const current: SuccessRateStats = currentData[0] || {
403→		total_sessions: 0,
404→		avg_success_score: 0,
405→		high_quality_sessions: 0,
406→	};
407→
408→	const previous: SuccessRateStats = previousData[0] || {
409→		total_sessions: 0,
410→		avg_success_score: 0,
411→		high_quality_sessions: 0,
412→	};
413→
414→	const currentSuccessRate =
415→		current.total_sessions > 0
416→			? (current.high_quality_sessions / current.total_sessions) * 100
417→			: 0;
418→
419→	const previousSuccessRate =
420→		previous.total_sessions > 0
421→			? (previous.high_quality_sessions / previous.total_sessions) * 100
422→			: 0;
423→
424→	return {
425→		current: {
426→			high_quality_sessions: current.high_quality_sessions,
427→			total_sessions: current.total_sessions,
428→			success_rate: currentSuccessRate,
429→		},
430→		previous: {
431→			high_quality_sessions: previous.high_quality_sessions,
432→			total_sessions: previous.total_sessions,
433→			success_rate: previousSuccessRate,
434→		},
435→		changes: {
436→			success_rate: currentSuccessRate - previousSuccessRate,
437→		},
438→	};
