359→		concurrency: flags.concurrency,
360→		upload: async (item, onRetry) => {
361→			const adapter = item.failure.source
362→				? getAdapter(item.failure.source)
363→				: claudeCodeAdapter;
364→			const sessionFile: SessionFile = {
365→				sessionId: item.failure.sessionId,
