    FROM rudel.session_analytics
    WHERE ${buildDateFilter(d)}
      AND organization_id = '${org}'
      ${filters}

    ORDER BY count DESC
  `;

	return queryClickhouse<{ bucket: string; count: number; percentage: number }>(
		query,
	);
}

